import java.util.*;

public class DijkstraExample {
    // Helper class to represent a node and its current shortest distance
    static class Node implements Comparable<Node> {
        int vertex, weight;
        Node(int v, int w) { vertex = v; weight = w; }

        @Override
        public int compareTo(Node other) {
            return Integer.compare(this.weight, other.weight);
        }
    }

    public static void dijkstra(List<List<Node>> adj, int src, int V) {
        // Initialize distances as infinity
        int[] dist = new int[V];
        Arrays.fill(dist, Integer.MAX_VALUE);
        dist[src] = 0;

        PriorityQueue<Node> pq = new PriorityQueue<>();
        pq.add(new Node(src, 0));

        while (!pq.isEmpty()) {
            Node current = pq.poll();
            int u = current.vertex;

            // If we found a longer path already in the queue, skip it
            if (current.weight > dist[u]) continue;

            // Check all neighbors of node u
            for (Node neighbor : adj.get(u)) {
                int v = neighbor.vertex;
                int weight = neighbor.weight;

                // Relaxation step: if a shorter path to v is found through u
                if (dist[u] + weight < dist[v]) {
                    dist[v] = dist[u] + weight;
                    pq.add(new Node(v, dist[v]));
                }
            }
        }

        // Print the results
        System.out.println("Vertex \t Distance from Source " + src);
        for (int i = 0; i < V; i++) {
            System.out.println(i + " \t\t " + (dist[i] == Integer.MAX_VALUE ? "INF" : dist[i]));
        }
    }

    public static void main(String[] args) {
        int V = 5;
        List<List<Node>> adj = new ArrayList<>();
        for (int i = 0; i < V; i++) adj.add(new ArrayList<>());

        // Adding edges: (u, v, weight)
        adj.get(0).add(new Node(1, 9));
        adj.get(0).add(new Node(2, 6));
        adj.get(1).add(new Node(3, 2));
        adj.get(2).add(new Node(1, 2));
        adj.get(2).add(new Node(3, 5));

        dijkstra(adj, 0, V);
    }
}

import java.util.*;

public class KahnsAlgorithm {
    public List<Integer> topologicalSort(int V, List<List<Integer>> adj) {
        // 1. Calculate in-degree for every vertex
        int[] inDegree = new int[V];
        for (int i = 0; i < V; i++) {
            for (int neighbor : adj.get(i)) {
                inDegree[neighbor]++;
            }
        }

        // 2. Add all vertices with in-degree 0 to a queue
        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < V; i++) {
            if (inDegree[i] == 0) {
                queue.add(i);
            }
        }

        List<Integer> topoOrder = new ArrayList<>();
        int count = 0;

        // 3. Process the queue
        while (!queue.isEmpty()) {
            int current = queue.poll();
            topoOrder.add(current);
            count++;

            // For each neighbor, reduce its in-degree
            for (int neighbor : adj.get(current)) {
                inDegree[neighbor]--;

                // If in-degree becomes 0, add to queue
                if (inDegree[neighbor] == 0) {
                    queue.add(neighbor);
                }
            }
        }

        // 4. Check for cycles
        if (count != V) {
            throw new RuntimeException("Graph contains a cycle; topological sort impossible.");
        }

        return topoOrder;
    }
}

import java.util.*;

public class TopologicalSortDFS {

    // Function to perform DFS and store the topological order in a stack
    private static void dfs(int node, boolean[] visited, Stack<Integer> stack, 
                            ArrayList<ArrayList<Integer>> adj) {
        // Mark the current node as visited
        visited[node] = true;

        // Traverse all adjacent vertices
        for (int neighbor : adj.get(node)) {
            if (!visited[neighbor]) {
                dfs(neighbor, visited, stack, adj);
            }
        }

        // After visiting all neighbors, push the current node to the stack
        stack.push(node);
    }

    // Function to return the topological sort of a Directed Acyclic Graph (DAG)
    public static int[] getTopoSort(int V, ArrayList<ArrayList<Integer>> adj) {
        Stack<Integer> stack = new Stack<>();
        boolean[] visited = new boolean[V];

        // Call DFS for every unvisited node
        for (int i = 0; i < V; i++) {
            if (!visited[i]) {
                dfs(i, visited, stack, adj);
            }
        }

        // Pop elements from stack to get the linear ordering
        int[] topoOrder = new int[V];
        int index = 0;
        while (!stack.isEmpty()) {
            topoOrder[index++] = stack.pop();
        }

        return topoOrder;
    }

    public static void main(String[] args) {
        int V = 6;
        ArrayList<ArrayList<Integer>> adj = new ArrayList<>(V);
        for (int i = 0; i < V; i++) adj.add(new ArrayList<>());

        // Example graph edges
        adj.get(5).add(2); adj.get(5).add(0);
        adj.get(4).add(0); adj.get(4).add(1);
        adj.get(2).add(3); adj.get(3).add(1);

        int[] result = getTopoSort(V, adj);
        System.out.println("Topological Sort: " + Arrays.toString(result));
    }
}

class Solution {
    public String trafficSignal(int timer) {
        if(timer == 0)
            return "Green";
        else if(timer == 30)
            return "Orange";
        else if(timer > 30 && timer <= 90)
            return "Red";
        else
            return "Invalid";
    }
}

class Solution {
    private int count(int num,int digit){
        int cnt = 0;
        while(num>0){
            if(num%10 == digit)
                cnt++;
            num = num/10;
        }
        return cnt;
    }
    public int countDigitOccurrences(int[] nums, int digit) {
        int tot = 0;
        for(int i:nums){
            tot += count(i,digit);
        }
        return tot;
    }
}
